```

2. Add authorization checks in handlers:
```typescript
export const createLocation: api.server.CreateLocationOperationHandler<
  application.Authentication
> = async (incomingRequest, authentication) => {
  if (!authentication?.apiKey && !authentication?.openId) {
    return { status: 401, parameters: {}, contentType: 'application/json', entity: () => ({ error: 'Unauthorized' }) };
  }
  // ... existing logic
};
```

