```typescript
function sanitizeFilename(name: string): string {
  return name.replace(/[\r\n"]/g, '').replace(/[^a-zA-Z0-9._-]/g, '_');
}

const rawFilename = searchParams.get('filename') ?? `${dayjs().toISOString()}-export`;
const filename = `${sanitizeFilename(rawFilename)}.pdf`;
```

